var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`귀하의 종신계약 권유에 대한 답을 산출하는 중.`,JPN:`終身契約勧誘への回答を算出中。`,ENG:`Looking for an appropriate answer to your lifetime contract offer....`,TWN:`對於您「終身契約」的提議，正在計算答案……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`사장과 함께라면 전선도 얼마든지 환영이다.`,JPN:`社長が一緒なら、たとえ戦線であろうと喜んで向かいます。`,ENG:`I can go to the battlefront if you want me to.`,TWN:`和老闆在一起的話，不管要我站上前線幾次，我都很樂意。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`하지만 기존에 수행하던 물자공급역할은 계속 본 차량에게 맡겨줬으면 한다.`,JPN:`ただし、既存の物資供給役を、引き続き本車両に任せていただきたいと思います。`,ENG:`But I'd like to stay in charge of transportation of supplies.`,TWN:`但是，既存並實行中的物資運輸作業，希望可以繼續交給本車輛執行。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`본 차량이 소속된 부대는 험지에 위치해있어서 비나 눈이 오면 물자공급이 어렵다.`,JPN:`本車両が所属する部隊は険しい地帯に位置しており、雨や雪が降れば物資供給が困難になります。`,ENG:`My unit, stationed in tough terrain, can easily be cut off from resupply when it rains or snows.`,TWN:`本車輛所屬部隊處於危險地帶，一旦發生降雨或降雪，物資供應會變得非常困難。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`하지만 본 차량은 귀사의 도움을 받아 보강을 거쳤기 때문에, 비나 눈이 와도 원활한 산악주행이 가능하다.`,JPN:`しかし、本車両は御社の協力を受け補強を施しているため、雨や雪が降っても円滑な山岳走行が可能です。`,ENG:`But thanks to your company, I'm now strong enough to drive through difficult terrain, rain or snow.`,TWN:`然而，本車輛藉由貴公司的幫助，經過補強後，就算雨雪來臨，也能平順地在山岳上行駛。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`......용인해주는 것인가.`,JPN:`……容認してくださるのですね。`,ENG:`... So, you'll let me.`,TWN:`……您是否能允許？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CARGO_SL_NULL_NULL`,text:{KOREA:`허가에 감사를 표한다.`,JPN:`許可していただき、感謝申し上げます。`,ENG:`Thank you for your permission.`,TWN:`感謝您的允許。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CARGO_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};